import { simpleGit } from 'simple-git'
import { pathExists } from '../utils/fs.js'

export interface WorktreeInfo {
  path: string
  branch: string
  commit: string
}

export async function createWorktree(
  repoRoot: string,
  worktreePath: string,
  branchName: string,
  baseBranch: string
): Promise<void> {
  const git = simpleGit(repoRoot)

  // Check if worktree path already exists (e.g. crash recovery)
  if (await pathExists(worktreePath)) {
    throw new Error(
      `Worktree path already exists: ${worktreePath}\n` +
        'If this is stale, remove it with: git worktree remove --force <path>'
    )
  }

  // Check if branch already exists
  const branches = await git.branchLocal()
  const branchExists = branches.all.includes(branchName)

  if (branchExists) {
    // Reuse existing branch without -b flag
    await git.raw(['worktree', 'add', worktreePath, branchName])
  } else {
    // Create new branch from base
    await git.raw(['worktree', 'add', '-b', branchName, worktreePath, baseBranch])
  }
}

export async function removeWorktree(repoRoot: string, worktreePath: string): Promise<void> {
  const git = simpleGit(repoRoot)
  await git.raw(['worktree', 'remove', '--force', worktreePath])
}

export async function listWorktrees(repoRoot: string): Promise<WorktreeInfo[]> {
  const git = simpleGit(repoRoot)
  const raw = await git.raw(['worktree', 'list', '--porcelain'])

  const worktrees: WorktreeInfo[] = []
  const blocks = raw.trim().split('\n\n')

  for (const block of blocks) {
    const lines = block.trim().split('\n')
    const info: Partial<WorktreeInfo> = {}
    for (const line of lines) {
      if (line.startsWith('worktree ')) info.path = line.slice(9)
      if (line.startsWith('HEAD ')) info.commit = line.slice(5)
      if (line.startsWith('branch ')) info.branch = line.slice(7)
    }
    if (info.path && info.commit) {
      worktrees.push(info as WorktreeInfo)
    }
  }

  return worktrees
}

export async function deleteBranch(repoRoot: string, branchName: string): Promise<void> {
  const git = simpleGit(repoRoot)
  await git.deleteLocalBranch(branchName, true)
}

export async function mergeBranch(
  repoRoot: string,
  branchName: string,
  targetBranch: string
): Promise<void> {
  const git = simpleGit(repoRoot)
  await git.checkout(targetBranch)
  await git.merge([branchName, '--no-ff', '-m', `Merge task branch: ${branchName}`])
}

import inquirer from 'inquirer'
import { SUPPORTED_AGENTS } from '../agents/index.js'
import type { TaskRecord } from '../core/state.js'

export async function promptTitle(): Promise<string> {
  const { title } = await inquirer.prompt<{ title: string }>([
    {
      type: 'input',
      name: 'title',
      message: 'Task title:',
      validate: (input: string) =>
        input.trim().length > 0 ? true : 'Title cannot be empty',
    },
  ])
  return title.trim()
}

export async function selectAgent(current?: string): Promise<string> {
  const agentDescriptions: Record<string, string> = {
    claude: 'Claude Code (recommended) — injects spec via CLAUDE.md',
    cursor: 'Cursor — opens worktree directory in GUI',
    codex: 'OpenAI Codex CLI — prints spec for manual paste',
    gemini: 'Gemini CLI — prints spec for manual paste',
  }

  const { agent } = await inquirer.prompt<{ agent: string }>([
    {
      type: 'list',
      name: 'agent',
      message: 'Which agent?',
      default: current ?? 'claude',
      choices: SUPPORTED_AGENTS.map((name) => ({
        name: agentDescriptions[name] ?? name,
        value: name,
      })),
    },
  ])
  return agent
}

export async function selectTask(tasks: TaskRecord[]): Promise<TaskRecord> {
  if (tasks.length === 1) return tasks[0]

  const { taskId } = await inquirer.prompt<{ taskId: string }>([
    {
      type: 'list',
      name: 'taskId',
      message: 'Which task?',
      choices: tasks.map((t) => ({
        name: `${t.title} ${t.id}`,
        value: t.id,
      })),
    },
  ])

  return tasks.find((t) => t.id === taskId)!
}

export async function confirmBaseBranch(detected: string): Promise<string> {
  const { branch } = await inquirer.prompt<{ branch: string }>([
    {
      type: 'input',
      name: 'branch',
      message: 'Base branch:',
      default: detected,
    },
  ])
  return branch.trim() || detected
}

export async function selectCompletionMethod(): Promise<'pr' | 'merge'> {
  const { method } = await inquirer.prompt<{ method: 'pr' | 'merge' }>([
    {
      type: 'list',
      name: 'method',
      message: 'How would you like to complete this task?',
      choices: [
        { name: 'Create PR via gh', value: 'pr' },
        { name: 'Merge directly to base branch', value: 'merge' },
      ],
    },
  ])
  return method
}

export async function confirmAction(message: string): Promise<boolean> {
  const { confirmed } = await inquirer.prompt<{ confirmed: boolean }>([
    {
      type: 'confirm',
      name: 'confirmed',
      message,
      default: true,
    },
  ])
  return confirmed
}

import { requireWorkspace } from '../core/workspace.js'
import { readState, writeState, upsertTask, getActiveTask } from '../core/state.js'
import { parseSpec } from '../core/spec.js'
import { updateSpecFrontmatter } from '../core/spec.js'
import { runReview } from '../review/engine.js'
import { formatReview } from '../review/reporter.js'
import { withSpinner } from '../ui/spinner.js'
import { blank, fatal, muted } from '../ui/output.js'
import chalk from 'chalk'

export async function runTaskReview(): Promise<void> {
  const workspace = await requireWorkspace(process.cwd())
  const state = await readState(workspace.stateFile)

  const task = getActiveTask(state)
  if (!task) {
    fatal(
      'No active task found.\n' +
        'Start a task first: agentstation task start'
    )
  }

  if (!task.branch) {
    fatal('Task has no branch — was it started with agentstation task start?')
  }

  const spec = await parseSpec(task.spec_path)

  const result = await withSpinner('Analyzing diff', () =>
    runReview(spec, workspace.gitRoot, task.branch!, state.base_branch)
  )

  // Print review report
  console.log(formatReview(result))

  // Update task status → review
  const updated = { ...task, status: 'review' as const, reviewed: new Date().toISOString() }
  await writeState(workspace.stateFile, upsertTask(state, updated))
  await updateSpecFrontmatter(task.spec_path, { status: 'review' })

  console.log(chalk.gray('Task status → review'))
  blank()
  muted('Next: agentstation task done')
  muted('      (or continue working and re-run agentstation task review)')
  blank()
}

import { requireWorkspace } from '../core/workspace.js'
import { readState, writeState, upsertTask, getDraftTasks, getActiveTask } from '../core/state.js'
import { parseSpec, updateSpecFrontmatter } from '../core/spec.js'
import { getBranchName, getWorktreePath } from '../core/task.js'
import { createWorktree } from '../git/worktree.js'
import { getAdapter } from '../agents/index.js'
import { selectAgent, selectTask } from '../ui/prompts.js'
import { withSpinner } from '../ui/spinner.js'
import { success, warn, blank, fatal, info, divider, muted } from '../ui/output.js'
import { which } from '../utils/which.js'
import chalk from 'chalk'

interface TaskStartOptions {
  agent?: string
  task?: string
}

export async function runTaskStart(opts: TaskStartOptions): Promise<void> {
  const workspace = await requireWorkspace(process.cwd())
  const state = await readState(workspace.stateFile)

  // Warn if there's already an active task
  const active = getActiveTask(state)
  if (active) {
    warn(`There is already an active task: "${active.title}"`)
    warn('Complete or review it before starting another.')
    blank()
    process.exit(1)
  }

  // Find the task to start
  let task = opts.task
    ? state.tasks.find((t) => t.id === opts.task || t.title.toLowerCase().includes(opts.task!.toLowerCase()))
    : null

  if (!task) {
    const drafts = getDraftTasks(state)
    if (drafts.length === 0) {
      fatal('No draft tasks found.\nCreate one with: agentstation task new "Title"')
    }
    task = await selectTask(drafts)
  }

  // Load the spec to get/set the agent
  const spec = await parseSpec(task.spec_path)

  // Determine agent
  let agentName = opts.agent ?? spec.frontmatter.agent
  if (!agentName) {
    agentName = await selectAgent()
  }

  const adapter = getAdapter(agentName)

  // Check agent binary availability
  const available = await which(agentName)
  if (!available) {
    warn(`Agent binary "${agentName}" not found in PATH — proceeding anyway.`)
  }

  const branchName = getBranchName(task)
  const worktreePath = getWorktreePath(workspace.worktreesDir, task)

  blank()
  console.log(chalk.bold(`Starting task: ${task.title}`))
  divider()
  info(`Branch:   ${branchName}`)
  info(`Worktree: .agentstation/worktrees/${worktreePath.split('/').pop()}`)
  info(`Agent:    ${adapter.displayName}`)
  blank()

  // Create worktree
  await withSpinner('Creating git worktree', () =>
    createWorktree(workspace.gitRoot, worktreePath, branchName, state.base_branch)
  )

  // Inject spec context
  await withSpinner(`Injecting spec → ${agentName === 'claude' ? 'CLAUDE.md' : 'context'}`, () =>
    adapter.inject(worktreePath, spec)
  )

  // Update task state
  task = {
    ...task,
    status: 'active',
    branch: branchName,
    worktree_path: worktreePath,
    started: new Date().toISOString(),
  }
  await writeState(workspace.stateFile, upsertTask(state, task))

  // Update spec frontmatter
  await updateSpecFrontmatter(task.spec_path, {
    status: 'active',
    agent: agentName,
    branch: branchName,
    worktree: worktreePath,
  })

  blank()
  console.log(chalk.bold(`Launching ${adapter.displayName}...`))
  divider()
  blank()

  // Launch agent (blocks for CLI agents, returns immediately for GUI)
  await adapter.launch(worktreePath)

  blank()
  divider()
  console.log(chalk.gray('Agent session ended.'))
  blank()
  info(`Task status: active`)
  blank()
  muted(`Next: agentstation task review`)
  blank()
}

